"use client";

import React, { useEffect, useMemo, useState } from "react";
import {
  ArrowLeft,
  BarChart2,
  ExternalLink,
  RefreshCw,
  Shield,
  Zap,
  X,
} from "lucide-react";

import type {
  AnalysisResult,
  ClinvarVariant,
  GeneBounds,
  GeneDetailsFromSearch,
  GeneFromSearch,
} from "~/utils/genome-api";
import {
  analyzeVariantWithAPI,
  fetchClinvarVariants,
  fetchGeneDetails,
} from "~/utils/genome-api";
import {
  getClassificationColorClasses,
  getNucleotideColorClass,
} from "~/utils/coloring-utils";

function parseRefAltFromTitle(title: string): { ref: string; alt: string } | null {
  const match = title.match(/(\w)>(\w)/);
  if (!match || match.length !== 3) return null;
  return { ref: match[1], alt: match[2] };
}

function parsePosition(location: string | undefined): number | null {
  if (!location) return null;
  const cleaned = location.replaceAll(",", "").trim();
  const value = parseInt(cleaned);
  return Number.isFinite(value) ? value : null;
}

function ConfidenceBar({
  confidence,
  accent,
}: {
  confidence: number;
  accent: "path" | "benign";
}) {
  const width = Math.max(0, Math.min(100, confidence * 100));
  const barClass = accent === "path" ? "bg-red-500" : "bg-emerald-500";
  return (
    <div className="mt-2">
      <div className="h-2 w-full overflow-hidden rounded-full bg-white/10">
        <div className={`h-2 ${barClass}`} style={{ width: `${width}%` }} />
      </div>
      <div className="mt-1 text-[11px] text-white/60">{Math.round(width)}%</div>
    </div>
  );
}

function PredictionBadge({ prediction }: { prediction: string }) {
  const lower = prediction.toLowerCase();
  const accent =
    lower.includes("pathogenic") ? "path" : lower.includes("benign") ? "benign" : "benign";
  return (
    <span
      className={`inline-flex items-center rounded-full border px-3 py-1 text-xs font-semibold ${
        accent === "path"
          ? "border-red-400/30 bg-red-500/10 text-red-200"
          : "border-emerald-400/30 bg-emerald-500/10 text-emerald-200"
      }`}
    >
      {prediction}
    </span>
  );
}

function VariantComparisonModal({
  comparisonVariant,
  onClose,
}: {
  comparisonVariant: ClinvarVariant | null;
  onClose: () => void;
}) {
  if (!comparisonVariant?.evo2Result) return null;

  const evo = comparisonVariant.evo2Result;
  const titleParts = parseRefAltFromTitle(comparisonVariant.title);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 p-4">
      <div className="w-full max-w-3xl overflow-hidden rounded-2xl border border-white/10 bg-[#0b1220] shadow-2xl">
        <div className="flex items-start justify-between gap-4 border-b border-white/10 p-5">
          <div>
            <div className="text-sm font-semibold text-white">ClinVar vs Evo2</div>
            <div className="mt-1 text-xs text-white/60">
              {comparisonVariant.clinvar_id} • {comparisonVariant.location}
            </div>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="rounded-xl bg-white/5 px-3 py-2 text-white/80 ring-1 ring-white/10 hover:bg-white/10"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="p-5">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="rounded-xl border border-white/10 bg-white/5 p-4">
              <div className="flex items-center justify-between gap-3">
                <div className="text-xs font-semibold text-white/70">ClinVar</div>
                <span
                  className={`rounded-lg px-3 py-1 text-xs ${getClassificationColorClasses(
                    comparisonVariant.classification,
                  )}`}
                >
                  {comparisonVariant.classification || "Unknown"}
                </span>
              </div>
              <div className="mt-2 text-sm font-medium text-white/90">
                {comparisonVariant.title}
              </div>
              {titleParts && (
                <div className="mt-3 text-xs text-white/70">
                  <span className={getNucleotideColorClass(titleParts.ref)}>{titleParts.ref}</span>
                  <span className="mx-1 text-white/40">&gt;</span>
                  <span className={getNucleotideColorClass(titleParts.alt)}>{titleParts.alt}</span>
                </div>
              )}
            </div>

            <div className="rounded-xl border border-white/10 bg-white/5 p-4">
              <div className="flex items-center justify-between gap-3">
                <div className="text-xs font-semibold text-white/70">Evo2</div>
                <span className="rounded-lg bg-white/5 px-3 py-1 text-xs font-semibold text-white/90 ring-1 ring-white/10">
                  <span className="inline-flex items-center gap-2">
                    <Shield className="h-3.5 w-3.5 text-[#f97316]" />
                    {evo.prediction}
                  </span>
                </span>
              </div>

              <div className="mt-3 text-xs text-white/60">Delta likelihood score</div>
              <div className="mt-1 text-xl font-semibold text-white">
                {evo.delta_score.toFixed(6)}
              </div>
              <ConfidenceBar
                confidence={evo.classification_confidence}
                accent={evo.prediction.toLowerCase().includes("pathogenic") ? "path" : "benign"}
              />
            </div>
          </div>

          <div className="mt-5 flex flex-wrap items-center justify-between gap-3">
            <a
              href={`https://www.ncbi.nlm.nih.gov/clinvar/variation/${comparisonVariant.clinvar_id}`}
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center gap-2 rounded-xl bg-white/5 px-3 py-2 text-xs text-white/80 ring-1 ring-white/10 hover:bg-white/10"
            >
              <ExternalLink className="h-4 w-4" />
              Open in ClinVar
            </a>
            <button
              type="button"
              onClick={onClose}
              className="rounded-xl bg-[#f97316] px-4 py-2 text-xs font-semibold text-black hover:bg-[#fb923c]"
            >
              Done
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function VariantAnalyzerPanel({
  gene,
  genomeId,
  geneBounds,
  onAnalysisResult,
}: {
  gene: GeneFromSearch;
  genomeId: string;
  geneBounds: GeneBounds;
  onAnalysisResult: (result: AnalysisResult) => void;
}) {
  const [position, setPosition] = useState<string>(geneBounds.min.toString());
  const [alternative, setAlternative] = useState<string>("A");
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<AnalysisResult | null>(null);

  const minBound = useMemo(() => Math.min(geneBounds.min, geneBounds.max), [geneBounds]);
  const maxBound = useMemo(() => Math.max(geneBounds.min, geneBounds.max), [geneBounds]);

  const submit = async () => {
    setError(null);
    const parsed = parseInt(position.replaceAll(",", ""));
    if (!Number.isFinite(parsed)) {
      setError("Position must be a number.");
      return;
    }
    if (parsed < minBound || parsed > maxBound) {
      setError(`Position must be within ${minBound.toLocaleString()} - ${maxBound.toLocaleString()}.`);
      return;
    }

    const alt = alternative.toUpperCase().trim();
    if (!/^[ATGC]$/.test(alt)) {
      setError("Alternative must be one of A, T, G, C.");
      return;
    }

    setIsAnalyzing(true);
    try {
      const data = await analyzeVariantWithAPI({
        position: parsed,
        alternative: alt,
        genomeId,
        chromosome: gene.chrom,
      });
      setResult(data);
      onAnalysisResult(data);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Variant analysis failed.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const accent = result?.prediction?.toLowerCase().includes("pathogenic") ? "path" : "benign";

  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
      <div className="flex items-center justify-between gap-3">
        <div>
          <div className="text-xs font-semibold text-white/60">Variant analyzer</div>
          <div className="mt-1 text-lg font-semibold text-white">
            {gene.symbol} • {gene.chrom}
          </div>
        </div>
        <div className="rounded-xl bg-white/5 p-2 ring-1 ring-white/10">
          <Zap className="h-4 w-4 text-[#f97316]" />
        </div>
      </div>

      <div className="mt-4 grid gap-3 sm:grid-cols-2">
        <div className="space-y-1">
          <div className="text-xs text-white/60">Variant position</div>
          <input
            value={position}
            onChange={(e) => setPosition(e.target.value)}
            className="w-full rounded-xl border border-white/10 bg-black/20 px-3 py-2 text-sm outline-none focus:border-[#f97316]/60"
            inputMode="numeric"
          />
        </div>
        <div className="space-y-1">
          <div className="text-xs text-white/60">Alternative base</div>
          <input
            value={alternative}
            onChange={(e) => setAlternative(e.target.value.toUpperCase().slice(0, 1))}
            className="w-full rounded-xl border border-white/10 bg-black/20 px-3 py-2 text-sm outline-none focus:border-[#f97316]/60"
            maxLength={1}
          />
        </div>
      </div>

      {result && (
        <div className="mt-4 rounded-xl border border-white/10 bg-black/20 p-4">
          <div className="flex items-start justify-between gap-3">
            <PredictionBadge prediction={result.prediction} />
            <div className="text-right text-xs text-white/60">
              Confidence
            </div>
          </div>

          <div className="mt-3 text-sm text-white/80">
            Substitution:{" "}
            <span className={`font-semibold ${getNucleotideColorClass(result.reference)}`}>
              {result.reference}
            </span>
            <span className="mx-2 text-white/40">&gt;</span>
            <span className={`font-semibold ${getNucleotideColorClass(result.alternative)}`}>
              {result.alternative}
            </span>
          </div>

          <div className="mt-3 text-xs text-white/60">Delta likelihood score</div>
          <div className="mt-1 text-2xl font-semibold text-white">{result.delta_score.toFixed(6)}</div>
          <ConfidenceBar confidence={result.classification_confidence} accent={accent} />
        </div>
      )}

      {error && (
        <div className="mt-4 rounded-xl border border-red-400/30 bg-red-500/10 px-3 py-2 text-xs text-red-200">
          {error}
        </div>
      )}

      <div className="mt-4 flex flex-col sm:flex-row gap-3 sm:items-center sm:justify-between">
        <div className="text-xs text-white/60">
          Bounds: {minBound.toLocaleString()} - {maxBound.toLocaleString()}
        </div>
        <button
          type="button"
          disabled={isAnalyzing}
          onClick={submit}
          className="rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black hover:bg-[#fb923c] disabled:opacity-60"
        >
          {isAnalyzing ? "Analyzing..." : "Analyze variant"}
        </button>
      </div>
    </div>
  );
}

function KnownVariantsPanel({
  gene,
  genomeId,
  geneBounds,
}: {
  gene: GeneFromSearch;
  genomeId: string;
  geneBounds: GeneBounds;
}) {
  const [variants, setVariants] = useState<ClinvarVariant[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState<ClinvarVariant | null>(null);

  const refresh = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const next = await fetchClinvarVariants(gene.chrom, geneBounds, genomeId);
      setVariants(next);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to fetch ClinVar variants.");
      setVariants([]);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    refresh();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [gene.chrom, geneBounds.min, geneBounds.max, genomeId]);

  const updateVariant = (id: string, patch: ClinvarVariant) => {
    setVariants((cur) => cur.map((v) => (v.clinvar_id === id ? patch : v)));
  };

  const analyzeClinvarVariant = async (variant: ClinvarVariant) => {
    const pos = parsePosition(variant.location);
    const parsedRefAlt = parseRefAltFromTitle(variant.title);
    if (!pos || !parsedRefAlt) {
      updateVariant(variant.clinvar_id, { ...variant, isAnalyzing: false, evo2Error: "Could not parse variant details." });
      return;
    }

    updateVariant(variant.clinvar_id, { ...variant, isAnalyzing: true, evo2Error: undefined });
    try {
      const data = await analyzeVariantWithAPI({
        position: pos,
        alternative: parsedRefAlt.alt,
        genomeId,
        chromosome: gene.chrom,
      });

      updateVariant(variant.clinvar_id, {
        ...variant,
        isAnalyzing: false,
        evo2Result: data,
      });
      setIsComparing({ ...variant, evo2Result: data });
    } catch (e) {
      updateVariant(variant.clinvar_id, {
        ...variant,
        isAnalyzing: false,
        evo2Error: e instanceof Error ? e.message : "Analysis failed",
      });
    }
  };

  const hasResults = variants.length > 0;

  return (
    <>
      <div className="rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
        <div className="flex items-start justify-between gap-4">
          <div>
            <div className="text-xs font-semibold text-white/60">ClinVar hints</div>
            <div className="mt-1 text-lg font-semibold text-white">
              Known single-nucleotide variants
            </div>
            <div className="mt-1 text-xs text-white/60">
              {variants.length} match{variants.length === 1 ? "" : "es"}
            </div>
          </div>
          <button
            type="button"
            onClick={refresh}
            disabled={isLoading}
            className="rounded-xl bg-white/5 px-3 py-2 text-xs font-semibold text-white/80 ring-1 ring-white/10 hover:bg-white/10 disabled:opacity-60"
          >
            <span className="inline-flex items-center gap-2">
              <RefreshCw className="h-4 w-4" />
              Refresh
            </span>
          </button>
        </div>

        {error && (
          <div className="mt-4 rounded-xl border border-red-400/30 bg-red-500/10 px-3 py-2 text-xs text-red-200">
            {error}
          </div>
        )}

        {isLoading ? (
          <div className="mt-5 space-y-3">
            {Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="h-16 animate-pulse rounded-xl bg-white/5 ring-1 ring-white/10" />
            ))}
          </div>
        ) : !hasResults ? (
          <div className="mt-5 rounded-xl border border-white/10 bg-black/20 p-4 text-sm text-white/70">
            No ClinVar variants found for this window.
          </div>
        ) : (
          <div className="mt-5 grid gap-3">
            {variants.map((v) => {
              const isSingle = v.variation_type?.toLowerCase().includes("single nucleotide");
              const canAnalyze = isSingle && !v.evo2Result && !v.isAnalyzing;
              const canCompare = !!v.evo2Result;
              const isBusy = !!v.isAnalyzing;

              return (
                <div
                  key={v.clinvar_id}
                  className="rounded-xl border border-white/10 bg-black/20 p-4"
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="min-w-0">
                      <div className="text-sm font-semibold text-white line-clamp-2">
                        {v.title}
                      </div>
                      <div className="mt-1 text-xs text-white/60">
                        Position: {v.location}
                      </div>
                    </div>
                    <div className="shrink-0 rounded-xl bg-white/5 px-3 py-1 text-[11px] text-white/70 ring-1 ring-white/10">
                      {v.variation_type}
                    </div>
                  </div>

                  <div className="mt-3 flex flex-wrap items-center gap-2">
                    <span
                      className={`rounded-lg px-3 py-1 text-xs ${getClassificationColorClasses(
                        v.classification,
                      )}`}
                    >
                      {v.classification || "Unknown"}
                    </span>
                    {v.evo2Error && (
                      <span className="rounded-lg bg-red-500/10 px-3 py-1 text-xs text-red-200 ring-1 ring-red-400/30">
                        {v.evo2Error}
                      </span>
                    )}
                  </div>

                  <div className="mt-4 flex flex-wrap items-center justify-between gap-3">
                    <button
                      type="button"
                      disabled={!canAnalyze}
                      onClick={() => analyzeClinvarVariant(v)}
                      className={`rounded-xl px-3 py-2 text-xs font-semibold ring-1 ring-white/10 ${
                        canAnalyze
                          ? "bg-[#f97316] text-black hover:bg-[#fb923c]"
                          : "bg-white/5 text-white/60 disabled:opacity-60"
                      }`}
                    >
                      {isBusy ? "Analyzing..." : canAnalyze ? "Run analysis" : "—"}
                    </button>

                    <div className="flex items-center gap-2">
                      <button
                        type="button"
                        disabled={!canCompare}
                        onClick={() => setIsComparing(v)}
                        className="rounded-xl bg-white/5 px-3 py-2 text-xs font-semibold text-white/80 ring-1 ring-white/10 hover:bg-white/10 disabled:opacity-60 disabled:pointer-events-none"
                      >
                        <span className="inline-flex items-center gap-2">
                          <BarChart2 className="h-4 w-4" />
                          Compare
                        </span>
                      </button>
                      <a
                        href={`https://www.ncbi.nlm.nih.gov/clinvar/variation/${v.clinvar_id}`}
                        target="_blank"
                        rel="noreferrer"
                        className="rounded-xl bg-white/5 px-3 py-2 text-xs font-semibold text-white/80 ring-1 ring-white/10 hover:bg-white/10"
                      >
                        View
                      </a>
                    </div>
                  </div>

                  {v.evo2Result && (
                    <div className="mt-3 flex items-center justify-between gap-3 rounded-xl bg-white/5 p-3 ring-1 ring-white/10">
                      <div className="flex items-center gap-2 text-xs text-white/70">
                        <Shield className="h-4 w-4 text-[#f97316]" />
                        Evo2 result
                      </div>
                      <div className="text-xs font-semibold text-white">
                        {v.evo2Result.prediction}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      <VariantComparisonModal comparisonVariant={isComparing} onClose={() => setIsComparing(null)} />
    </>
  );
}

export default function GeneViewerRedesigned({
  gene,
  genomeId,
  onClose,
}: {
  gene: GeneFromSearch;
  genomeId: string;
  onClose: () => void;
}) {
  const [geneDetail, setGeneDetail] = useState<GeneDetailsFromSearch | null>(null);
  const [geneBounds, setGeneBounds] = useState<GeneBounds | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [analysisEcho, setAnalysisEcho] = useState<AnalysisResult | null>(null);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      if (!gene.gene_id) {
        setError("This gene result has no gene_id, cannot load details.");
        setIsLoading(false);
        return;
      }
      setIsLoading(true);
      setError(null);
      try {
        const { geneDetails, geneBounds: bounds } = await fetchGeneDetails(gene.gene_id);
        if (cancelled) return;
        setGeneDetail(geneDetails);
        setGeneBounds(bounds);
        if (!bounds) setError("Could not load gene coordinate bounds.");
      } catch (e) {
        if (cancelled) return;
        setError(e instanceof Error ? e.message : "Failed to load gene details.");
      } finally {
        if (!cancelled) setIsLoading(false);
      }
    };
    run();
    return () => {
      cancelled = true;
    };
  }, [gene.gene_id]);

  const bounds = geneBounds;
  const minBound = bounds ? Math.min(bounds.min, bounds.max) : null;
  const maxBound = bounds ? Math.max(bounds.min, bounds.max) : null;

  return (
    <div className="min-h-screen bg-[#050813] text-white">
      <header className="sticky top-0 z-[50] border-b border-white/10 bg-[#050813]/80 backdrop-blur px-4 py-4">
        <div className="mx-auto flex max-w-6xl items-center justify-between gap-3">
          <button
            type="button"
            onClick={onClose}
            className="inline-flex items-center gap-2 rounded-xl bg-white/5 px-3 py-2 text-sm font-semibold text-white/80 ring-1 ring-white/10 hover:bg-white/10"
          >
            <ArrowLeft className="h-4 w-4" />
            Back
          </button>
          <div className="text-right">
            <div className="text-xs text-white/60">Current gene</div>
            <div className="text-sm font-semibold text-white">
              {gene.symbol} • {gene.chrom}
            </div>
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-6xl px-4 py-6">
        {isLoading ? (
          <div className="rounded-2xl border border-white/10 bg-white/5 p-6">
            <div className="h-6 w-40 animate-pulse rounded bg-white/10" />
            <div className="mt-4 h-32 w-full animate-pulse rounded bg-white/5 ring-1 ring-white/10" />
          </div>
        ) : error ? (
          <div className="rounded-2xl border border-red-400/30 bg-red-500/10 p-4 text-sm text-red-200">
            {error}
          </div>
        ) : !bounds ? (
          <div className="rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-white/70">
            Missing bounds.
          </div>
        ) : (
          <div className="grid gap-5 lg:grid-cols-12">
            <section className="lg:col-span-7">
              <VariantAnalyzerPanel
                gene={gene}
                genomeId={genomeId}
                geneBounds={bounds}
                onAnalysisResult={(r) => setAnalysisEcho(r)}
              />

              {analysisEcho && (
                <div className="mt-4 rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
                  <div className="text-xs font-semibold text-white/60">Latest analysis</div>
                  <div className="mt-2 flex flex-wrap items-center gap-3">
                    <PredictionBadge prediction={analysisEcho.prediction} />
                    <span className="text-sm font-semibold text-white">
                      Δ {analysisEcho.delta_score.toFixed(6)}
                    </span>
                    <span className="text-xs text-white/60">
                      {analysisEcho.position.toLocaleString()}
                    </span>
                  </div>
                </div>
              )}
            </section>

            <aside className="lg:col-span-5">
              <KnownVariantsPanel gene={gene} genomeId={genomeId} geneBounds={bounds} />
            </aside>

            <section className="lg:col-span-12">
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <div className="text-xs font-semibold text-white/60">Gene summary</div>
                    <div className="mt-1 text-lg font-semibold text-white">
                      {geneDetail?.organism
                        ? `${geneDetail.organism.scientificname} • ${gene.symbol}`
                        : gene.symbol}
                    </div>
                  </div>
                  <div className="text-right text-xs text-white/60">
                    Window size: {(bounds.max - bounds.min + 1).toLocaleString()} bp
                  </div>
                </div>

                {geneDetail?.summary && (
                  <div className="mt-4 text-sm text-white/70 leading-relaxed">
                    {geneDetail.summary}
                  </div>
                )}

                <div className="mt-4 grid gap-3 sm:grid-cols-2">
                  <div className="rounded-xl border border-white/10 bg-black/20 p-3">
                    <div className="text-xs font-semibold text-white/60">Coordinates</div>
                    <div className="mt-1 text-sm font-semibold text-white">
                      {minBound?.toLocaleString()} - {maxBound?.toLocaleString()}
                    </div>
                  </div>
                  <div className="rounded-xl border border-white/10 bg-black/20 p-3">
                    <div className="text-xs font-semibold text-white/60">Chromosome</div>
                    <div className="mt-1 text-sm font-semibold text-white">{gene.chrom}</div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        )}
      </main>
    </div>
  );
}

