"use client";

import { useEffect, useMemo, useState } from "react";
import { Search, Sparkles } from "lucide-react";

import type {
  ChromosomeFromSeach,
  GeneFromSearch,
  GenomeAssemblyFromSearch,
} from "~/utils/genome-api";
import {
  getAvailableGenomes,
  getGenomeChromosomes,
  searchGenes,
} from "~/utils/genome-api";
import GeneViewerRedesigned from "./gene-viewer-redesigned";

type ChromFilter = "selected" | "any";

export default function HomeRedesigned() {
  const [genomes, setGenomes] = useState<GenomeAssemblyFromSearch[]>([]);
  const [selectedGenome, setSelectedGenome] = useState<string>("hg38");

  const [chromosomes, setChromosomes] = useState<ChromosomeFromSeach[]>([]);
  const [selectedChromosome, setSelectedChromosome] = useState<string>("chr1");

  const [chromFilter, setChromFilter] = useState<ChromFilter>("selected");

  const [query, setQuery] = useState<string>("");
  const [results, setResults] = useState<GeneFromSearch[]>([]);

  const [selectedGene, setSelectedGene] = useState<GeneFromSearch | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      try {
        setIsLoading(true);
        setError(null);
        const data = await getAvailableGenomes();
        const human = data.genomes?.["Human"] ?? [];
        if (!cancelled) setGenomes(human);
      } catch {
        if (!cancelled) setError("Failed to load genome assemblies.");
      } finally {
        if (!cancelled) setIsLoading(false);
      }
    };
    run();
    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      try {
        setIsLoading(true);
        setError(null);
        const data = await getGenomeChromosomes(selectedGenome);
        if (!cancelled) {
          setChromosomes(data.chromosomes);
          setSelectedChromosome(data.chromosomes?.[0]?.name ?? "chr1");
        }
      } catch {
        if (!cancelled) setError("Failed to load chromosome list.");
      } finally {
        if (!cancelled) setIsLoading(false);
      }
    };
    run();
    return () => {
      cancelled = true;
    };
  }, [selectedGenome]);

  const selectedGenomeLabel = useMemo(() => {
    const match = genomes.find((g) => g.id === selectedGenome);
    return match ? `${match.id} • ${match.name}` : selectedGenome;
  }, [genomes, selectedGenome]);

  const runSearch = async () => {
    if (!query.trim()) return;
    setIsLoading(true);
    setError(null);
    try {
      const data = await searchGenes(query.trim(), selectedGenome);
      const next = data.results ?? [];
      const filtered = next.filter((g) => g.chrom === selectedChromosome);
      setResults(filtered);
    } catch {
      setError("Gene search failed. Try a different query.");
    } finally {
      setIsLoading(false);
    }
  };

  const quickBRCA1 = async () => {
    const nextQuery = "BRCA1";
    setQuery(nextQuery);
    setChromFilter("selected");

    setIsLoading(true);
    setError(null);
    try {
      const data = await searchGenes(nextQuery, selectedGenome);
      const next = data.results ?? [];
      const filtered =
        chromFilter === "any"
          ? next
          : next.filter((g) => g.chrom === selectedChromosome);
      setResults(filtered);
    } catch {
      setError("Gene search failed. Try BRCA1 again.");
    } finally {
      setIsLoading(false);
    }
  };

  if (selectedGene) {
    return (
      <GeneViewerRedesigned
        gene={selectedGene}
        genomeId={selectedGenome}
        onClose={() => setSelectedGene(null)}
      />
    );
  }

  return (
    <div className="min-h-screen bg-[#050813] text-white">
      <div className="relative overflow-hidden">
        <div className="pointer-events-none absolute -top-40 left-1/2 h-[520px] w-[520px] -translate-x-1/2 rounded-full bg-[#0ea5e9]/20 blur-3xl" />
        <div className="pointer-events-none absolute -bottom-60 left-[-120px] h-[520px] w-[520px] rounded-full bg-[#22c55e]/15 blur-3xl" />
        <header className="relative border-b border-white/10">
          <div className="mx-auto flex max-w-6xl items-center justify-between px-4 py-4 sm:px-6">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/10 ring-1 ring-white/10">
                <Sparkles className="h-5 w-5 text-[#f97316]" />
              </div>
              <div>
                <div className="text-sm font-medium text-white/70">
                  HelixMind
                </div>
                <div className="text-lg font-semibold tracking-wide">
                  Evo2 Variant Console
                </div>
              </div>
            </div>
            <div className="hidden text-right sm:block">
              <div className="text-xs text-white/60">Genome-aware variant scoring</div>
              <div className="text-xs text-white/80">{selectedGenomeLabel}</div>
            </div>
          </div>
        </header>

        <main className="mx-auto max-w-6xl px-4 py-8 sm:px-6">
          <div className="grid gap-6 lg:grid-cols-12">
            <section className="lg:col-span-4">
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
                <div className="mb-4">
                  <div className="text-xs font-medium text-white/60">
                    Step 1 • Choose genome
                  </div>
                </div>

                <label className="block text-xs font-medium text-white/70">
                  Genome Assembly
                </label>
                <select
                  value={selectedGenome}
                  onChange={(e) => setSelectedGenome(e.target.value)}
                  className="mt-2 w-full rounded-xl border border-white/10 bg-black/20 px-3 py-2 text-sm outline-none ring-0 focus:border-[#f97316]/60"
                >
                  {genomes.map((g) => (
                    <option key={g.id} value={g.id}>
                      {g.id} - {g.name}
                    </option>
                  ))}
                </select>

                <div className="mt-5">
                  <div className="text-xs font-medium text-white/60">
                    Step 2 • Chromosome focus
                  </div>
                  <div className="mt-2 flex items-center gap-2">
                    <button
                      type="button"
                      onClick={() => setChromFilter("selected")}
                      className={`rounded-full px-3 py-1 text-xs ring-1 ring-white/10 ${
                        chromFilter === "selected"
                          ? "bg-[#f97316] text-black"
                          : "bg-transparent text-white/80 hover:bg-white/5"
                      }`}
                    >
                      Selected
                    </button>
                    <button
                      type="button"
                      onClick={() => setChromFilter("any")}
                      className={`rounded-full px-3 py-1 text-xs ring-1 ring-white/10 ${
                        chromFilter === "any"
                          ? "bg-[#22c55e] text-black"
                          : "bg-transparent text-white/80 hover:bg-white/5"
                      }`}
                    >
                      Any chromosome
                    </button>
                  </div>

                  <div className="mt-3 max-h-24 overflow-auto rounded-xl border border-white/10 bg-black/15 p-2">
                    <div className="flex gap-2">
                      {chromosomes.map((chrom) => {
                        const active = chrom.name === selectedChromosome;
                        return (
                          <button
                            key={chrom.name}
                            type="button"
                            onClick={() => setSelectedChromosome(chrom.name)}
                            className={`flex-shrink-0 rounded-lg px-2 py-1 text-xs ring-1 ring-white/10 ${
                              active
                                ? "bg-white text-black"
                                : "bg-transparent text-white/75 hover:bg-white/5"
                            }`}
                          >
                            {chrom.name}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="mt-5">
                  <div className="text-xs font-medium text-white/60">
                    Step 3 • Find a gene
                  </div>
                  <div className="mt-2 flex gap-2">
                    <div className="flex-1">
                      <input
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        placeholder="Try: BRCA1, TP53, EGFR..."
                        className="w-full rounded-xl border border-white/10 bg-black/20 px-3 py-2 text-sm outline-none focus:border-[#f97316]/60"
                        onKeyDown={(e) => {
                          if (e.key === "Enter") runSearch();
                        }}
                      />
                    </div>
                    <button
                      type="button"
                      onClick={runSearch}
                      disabled={isLoading || !query.trim()}
                      className="rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black disabled:opacity-60"
                    >
                      <span className="inline-flex items-center gap-2">
                        <Search className="h-4 w-4" />
                        Search
                      </span>
                    </button>
                  </div>

                  <div className="mt-3">
                    <button
                      type="button"
                      onClick={quickBRCA1}
                      className="text-xs text-white/70 hover:text-white"
                    >
                      Quick fill: BRCA1
                    </button>
                  </div>
                </div>

                {error && (
                  <div className="mt-4 rounded-xl border border-red-400/30 bg-red-500/10 px-3 py-2 text-xs text-red-200">
                    {error}
                  </div>
                )}
              </div>
            </section>

            <section className="lg:col-span-8">
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4 sm:p-5">
                <div className="flex items-center justify-between gap-4">
                  <div>
                    <div className="text-xs font-medium text-white/60">
                      Results
                    </div>
                    <div className="mt-1 text-sm text-white/80">
                      {isLoading
                        ? "Searching..."
                        : `${results.length} gene${results.length === 1 ? "" : "s"} ready`}
                    </div>
                  </div>
                  {isLoading && (
                    <div className="flex items-center gap-2 text-xs text-white/60">
                      <div className="h-2 w-2 animate-pulse rounded-full bg-[#f97316]" />
                      Loading
                    </div>
                  )}
                </div>

                {results.length === 0 && !isLoading ? (
                  <div className="mt-6 rounded-xl border border-white/10 bg-black/10 p-4 text-sm text-white/70">
                    No genes found for your current query/filter.
                  </div>
                ) : (
                  <div className="mt-5 grid gap-3 sm:grid-cols-2">
                    {results.map((gene) => (
                      <button
                        key={`${gene.symbol}-${gene.chrom}`}
                        type="button"
                        onClick={() => setSelectedGene(gene)}
                        className="group rounded-xl border border-white/10 bg-black/10 p-4 text-left transition hover:border-[#f97316]/40 hover:bg-white/5"
                      >
                        <div className="flex items-start justify-between gap-3">
                          <div>
                            <div className="text-sm font-semibold">
                              {gene.symbol}
                            </div>
                            <div className="mt-1 text-xs text-white/70 line-clamp-2">
                              {gene.name}
                            </div>
                          </div>
                          <div className="flex-shrink-0 rounded-lg bg-white/10 px-2 py-1 text-[11px] text-white/80 ring-1 ring-white/10">
                            {gene.chrom}
                          </div>
                        </div>
                        <div className="mt-3 flex items-center justify-between text-xs text-white/55">
                          <span className="group-hover:text-white/80">
                            Open gene viewer
                          </span>
                          <span className="text-[#f97316] group-hover:text-[#fb923c]">
                            →
                          </span>
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </section>
          </div>
        </main>
      </div>
    </div>
  );
}

